import{_ as a}from"./Menu.edeb1320.js";import{u as l}from"./composables.4a9b2b71.js";import{r as e,a as o,e as r,b as d,f as i,o as c}from"./entry.787c95cd.js";const u=""+new URL("schema-3-pilier.cc09ec0d.png",import.meta.url).href,p=""+new URL("double-diamant.95f32a9c.png",import.meta.url).href,m={class:"banniere"},g=i('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>Le Design Thinking</h1><div class="projettitre"></div> 20 ao\xFBt 2022 \xB7 2 min </div><div class="colonne"></div></div></div></div>',1),h=i('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> S&#39;il est une m\xE9thodologie qui traverse les d\xE9cennies sans prendre une ride, c&#39;est bien le design thinking ! Adopt\xE9 dans les ann\xE9es 1980, le design thinking est une m\xE9thode qui allie des phases de divergence, de convergence, des ateliers d&#39;alignement, mais surtout une d\xE9marche centr\xE9e utilisateur. Son but, aller plus vite, plus loin, mais surtout dans la bonne direction ! </p><h2>Pourquoi utiliser cette m\xE9thode ?</h2> Un des objectifs de cette m\xE9thode et de trouver des solutions innovantes tout en r\xE9duisant les incertitudes. Un bon projet design est d\xE9fini \xE0 la rencontre de ces 3 piliers : la viabilit\xE9 \xE9conomique, la d\xE9sirabilit\xE9 du produit aupr\xE8s du public cible et sa faisabilit\xE9 technique. <img src="'+u+'" loading="lazy" alt="sch\xE9ma des piliers du design thinking"><h2>Comment fonctionne un projet design Thinking ?</h2><p>Le design thinking est une m\xE9thode compos\xE9e de 5 \xE9tapes : <ul><li><b>L&#39;immersion</b>, consiste \xE0 se mettre \xE0 la place de l&#39;utilisateur, comprendre ses besoins, ses probl\xE8mes</li><li><b>L&#39;analyse de l&#39;exploration</b>, consiste \xE0 trier et qualifier les insights de la phase d&#39;exploration </li><li><b>l&#39;id\xE9ation</b>, trouver des id\xE9es \xE0 partir de la synth\xE8se de l&#39;exploration</li><li><b>Prototypage</b>, reprendre les sketchs et id\xE9es pour les rendre plus tangibles et testable</li><li><b>L&#39;impl\xE9mentation</b>, tester le prototypage avec des utilisateurs,<br> prendre en compte leurs retours et am\xE9liorer le projet</li></ul></p><p> Ces 5 \xE9tapes prennent souvent la forme de ce qu&#39;on appelle le <b>double diamant</b> : </p><img src="'+p+'" loading="lazy" alt="sch\xE9ma du double diamant"></div></div></article>',1),q={__name:"le-design-thinking",setup(b){const s=e("Le Design Thinking - Lucas Lacroix"),t=e("S'il est une m\xE9thodologie qui traverse les d\xE9cennies sans prendre une ride, c'est bien le design thinking ! Adopt\xE9 dans les ann\xE9es 1980, le design thinking est une m\xE9thode qui allie des phases de divergence, de convergence, des ateliers d'alignement");return l({title:s,meta:[{name:"description",content:t}]}),(v,_)=>{const n=a;return c(),o("div",null,[r("div",m,[d(n),g]),h])}}};export{q as default};
